 1	import * as React from 'react';
 2	import { useGetInternalClusterDetails } from '@odf/core/redux/utils';
 3	import HealthItem from '@odf/shared/dashboards/status-card/HealthItem';
 4	import { PodModel } from '@odf/shared/models';
 5	import { PodKind } from '@odf/shared/types';
 6	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 7	import {
 8	  referenceForModel,
 9	  getPodStatus,
10	  getPodHealthState,
11	} from '@odf/shared/utils';
12	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
13	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
14	
15	const nfsPodResource = (clusterNs: string, clusterName: string) => ({
16	  isList: true,
17	  kind: referenceForModel(PodModel),
18	  namespace: clusterNs,
19	  selector: {
20	    matchLabels: {
21	      app: 'rook-ceph-nfs',
22	      ceph_nfs: `${clusterName}-cephnfs`,
23	    },
24	  },
25	});
26	
27	export const StatusCard: React.FC = () => {
28	  const { t } = useCustomTranslation();
29	
30	  const { clusterNamespace: clusterNs, clusterName } =
31	    useGetInternalClusterDetails();
32	
33	  const [nfsPods, nfsPodsLoaded, nfsPodsLoadError] = useK8sWatchResource<
34	    PodKind[]
35	  >(nfsPodResource(clusterNs, clusterName));
36	
37	  const serverHealthState = getPodHealthState(
38	    getPodStatus(nfsPods?.[0]),
39	    !nfsPodsLoaded,
40	    nfsPodsLoadError
41	  );
42	
43	  return (
44	    <Card data-test="nfs-status-card">
45	      <CardHeader>
46	        <CardTitle>{t('Status')}</CardTitle>
47	      </CardHeader>
48	      <CardBody>
49	        <HealthItem
50	          title={t('Server health')}
51	          state={serverHealthState.state}
52	        />
53	      </CardBody>
54	    </Card>
55	  );
56	};

